window.bookSummaryJSON = "<p>A Boston Globe-Horn Book Honor Book and ALA Notable and Best of the Year in Young Adult Fiction, <i>Howl's Moving Castle</i> is by acclaimed fantasy writer Diane Wynne Jones and was transformed into an Academy Award nominated animated motion picture by Hayao Miyazaki. On a rare venture out from her step-mother's hat shop, Sophie attracts the attention of a witch, who casts a terrible spell transforming the young girl into an old crone.</p>"; 
